const body = $input.first().json.body || $input.first().json;
const remoteJid = body?.data?.key?.remoteJid || body?.data?.remoteJid || body?.remoteJid || body?.key?.remoteJid || '';
const fromMe = body?.data?.key?.fromMe === true;
const isGroup = remoteJid.includes('@g.us');
const isNewsletter = remoteJid.includes('@newsletter');
const isLid = remoteJid.includes('@lid');
const numeroLimpo = remoteJid.replace('@s.whatsapp.net','').replace('@c.us','').replace('@lid','_lid');
const msgData = body?.data?.message || {};
const messageType = body?.data?.messageType || Object.keys(msgData)[0] || '';
let mensagem = '';
let localizacao = null;
if (messageType === 'locationMessage' || msgData.locationMessage) {
  const loc = msgData.locationMessage || {};
  mensagem = '__LOCALIZACAO__';
  localizacao = { lat: loc.degreesLatitude || 0, lng: loc.degreesLongitude || 0, nome: loc.name || '' };
} else {
  mensagem = (msgData.conversation || msgData.extendedTextMessage?.text || msgData.imageMessage?.caption || msgData.documentMessage?.caption || '').trim().toLowerCase();
}
const pushName = body?.data?.pushName || body?.data?.verifiedBizName || 'Cliente';
const messageId = body?.data?.key?.id || '';
const timestamp = body?.data?.messageTimestamp || Date.now();

// === BLOQUEIO DE ATENDIMENTO HUMANO ===
const staticData = $getWorkflowStaticData('global');
if (!staticData.memoriaClientes) staticData.memoriaClientes = {};
const memoria = staticData.memoriaClientes;
const INATIVIDADE_30MIN = 30 * 60 * 1000;
const PALAVRAS_RESET_BOT = ['bot', 'atendimento automatico', 'atendimento automático', 'opcoes'];

if (fromMe && remoteJid) {
  if (!memoria[remoteJid]) {
    memoria[remoteJid] = { estado: 'inicio', ultima_intencao: null, etapa: 'nova_conversa', ultima_interacao: Date.now() };
  }
  memoria[remoteJid].atendimentoHumano = true;
  memoria[remoteJid].ultimaInteracaoHumana = Date.now();
}

let bloqueadoPorHumano = false;
if (!fromMe && memoria[remoteJid]?.atendimentoHumano === true) {
  const pedindoBot = PALAVRAS_RESET_BOT.includes(mensagem);
  const inativo = Date.now() - (memoria[remoteJid].ultimaInteracaoHumana || 0) > INATIVIDADE_30MIN;
  if (pedindoBot || inativo) {
    memoria[remoteJid].atendimentoHumano = false;
  } else {
    memoria[remoteJid].ultimaInteracaoHumana = Date.now();
    bloqueadoPorHumano = true;
  }
}
// === FIM BLOQUEIO ===

const podeResponder = !fromMe && !isGroup && !isNewsletter && remoteJid !== '' && !bloqueadoPorHumano;
return [{ json: { remoteJid, numeroLimpo, mensagem, mensagemOriginal: mensagem, localizacao, messageType, pushName, messageId, timestamp, fromMe, isGroup, isLid, podeResponder, bloqueadoPorHumano, _raw: body } }];

const dados = $input.first().json;
const remoteJid = dados.remoteJid;
const mensagem = dados.mensagem;
const staticData = $getWorkflowStaticData('global');
if (!staticData.sessoes) staticData.sessoes = {};
const agora = Date.now();
const TIMEOUT = 30 * 60 * 1000;
for (const jid in staticData.sessoes) {
  if (agora - (staticData.sessoes[jid].ultimaAtividade || 0) > TIMEOUT) delete staticData.sessoes[jid];
}
let sessao = staticData.sessoes[remoteJid];
if (!sessao) {
  sessao = { estado: 'inicio', ultimaAtividade: agora, nome: dados.pushName };
  staticData.sessoes[remoteJid] = sessao;
}
sessao.ultimaAtividade = agora;
const reset = ['oi', 'ola', 'bom dia', 'boa tarde', 'boa noite', 'reiniciar', 'inicio', 'começar'];
if (reset.includes(mensagem)) sessao.estado = 'inicio';
const estadoAtual = sessao.estado;
const temHistorico = Array.isArray(sessao.historico) && sessao.historico.length > 0;
const rota = (estadoAtual === 'inicio' && !temHistorico) ? 'menu_principal' : 'processador';
return [{ json: { ...dados, estadoAtual, rota, sessao } }];

const dados = $input.first().json;
const nome = dados.pushName || '';
const staticData = $getWorkflowStaticData('global');
const sessao = staticData.sessoes[dados.remoteJid];
if (sessao) sessao.estado = 'aguardando';

const LINK_CARDAPIO = '{{LINK_CARDAPIO}}';
const msg = (dados.mensagem || '').trim().toLowerCase();

// Se já chegou com intenção de cardápio/pedido, responde direto sem saudação dupla
const querCardapio = /card[áa]pio|menu|o que tem|ver (os )?pratos?|op[çc][õo]es?/.test(msg);
const querPedir = /quero|vou querer|p[eê]de|me manda|queria/.test(msg);

let texto;
if (querCardapio) {
  texto = `Aqui está nosso cardápio 👇\n${LINK_CARDAPIO}\n\nViu algo que gostou? Me fala que eu anoto o pedido 😊`;
} else if (querPedir) {
  texto = nome ? `Boa, ${nome.split(' ')[0]}! Me fala o que você vai querer 😊` : 'Boa! Me fala o que você vai querer 😊';
} else {
  const primeiro = nome ? nome.split(' ')[0] : '';
  texto = primeiro
    ? `Fala, ${primeiro}! 👋 Aqui é o Grill Central. Me diz o que vai querer que já monto teu pedido 😊`
    : `Fala! 👋 Aqui é o Grill Central. Me diz o que vai querer que já monto teu pedido 😊`;
}

return [{ json: { ...dados, textoResposta: texto } }];

const dados = $input.first().json;
const msg = (dados.mensagem || '').trim().toLowerCase();
const msgOrig = dados.mensagemOriginal || msg;
const nome = dados.pushName || '';
const staticData = $getWorkflowStaticData('global');
const sessao = staticData.sessoes[dados.remoteJid];
const hBR = new Date(Date.now() - 3 * 60 * 60 * 1000);
const hora = hBR.getHours();
const diaSemana = hBR.getDay();

const LINK_CARDAPIO = '{{LINK_CARDAPIO}}';

// ─── NORMALIZE ────────────────────────────────────────────────────────────────
function normalizeText(text) {
  return (text || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/-/g, ' ')
    .replace(/[^\w\s]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

// ─── MENU SERVICE ─────────────────────────────────────────────────────────────
// TODO: PDV — trocar por: const PRODUTOS = await PDVAdapter.getProducts();
const MOCK_PRODUCTS = [
  // XIS
  { id:'xs001',   name:'X Salada',                          aliases:['x salada','xis salada','salada'],                                              price:29.9,  active:true, category:'XIS'        },
  { id:'xc001',   name:'X Coração',                         aliases:['x coracao','xis coracao','coração','coracao'],                                  price:31.0,  active:true, category:'XIS'        },
  { id:'xcal001', name:'X Calabresa',                       aliases:['x calabresa','xis calabresa','calabresa'],                                      price:31.0,  active:true, category:'XIS'        },
  { id:'xcos001', name:'X Costelão',                        aliases:['x costelao','xis costelao','costelao','costelão'],                               price:33.0,  active:true, category:'XIS'        },
  { id:'xb001',   name:'X Bacon',                           aliases:['x bacon','xbacon','bacon','xis bacon'],                                         price:33.0,  active:true, category:'XIS'        },
  { id:'xfm001',  name:'X Filé Mignon',                     aliases:['x file','x file mignon','file mignon','filé mignon'],                           price:45.0,  active:true, category:'XIS'        },
  { id:'xa001',   name:'X Alcatra',                         aliases:['x alcatra','alcatra'],                                                          price:34.0,  active:true, category:'XIS'        },
  { id:'xf001',   name:'X Frango',                          aliases:['x frango','frango'],                                                            price:31.0,  active:true, category:'XIS'        },
  // ALHO NEGRO
  { id:'pan001',  name:'Pão de Alho Negro com Alcatra',     aliases:['alho negro alcatra','pao alho alcatra','alcatra alho negro'],                    price:42.0,  active:true, category:'ALHO_NEGRO' },
  { id:'pan002',  name:'Pão de Alho Negro com Coração e Bacon', aliases:['alho negro coracao bacon','pao alho coracao bacon'],                        price:39.9,  active:true, category:'ALHO_NEGRO' },
  { id:'pan003',  name:'Pão de Alho Negro com Costela Desfiada', aliases:['alho negro costela','pao alho costela'],                                   price:39.9,  active:true, category:'ALHO_NEGRO' },
  // PORÇÕES
  { id:'batm001', name:'Batata Frita M',                    aliases:['batata media','batata m'],                                                      price:15.0,  active:true, category:'PORCOES'    },
  { id:'batg001', name:'Batata Frita G',                    aliases:['batata grande','batata g'],                                                     price:22.0,  active:true, category:'PORCOES'    },
  { id:'batbm001',name:'Batata com Bacon M',                aliases:['batata bacon media','batata bacon m'],                                           price:22.0,  active:true, category:'PORCOES'    },
  { id:'batbg001',name:'Batata com Bacon G',                aliases:['batata bacon grande','batata bacon g'],                                          price:29.0,  active:true, category:'PORCOES'    },
  // BEBIDAS
  { id:'cer001',  name:'Cerveja Long Neck',                 aliases:['long neck','heineken','corona'],                                                price:12.0,  active:true, category:'BEBIDAS'    },
  { id:'cer002',  name:'Cerveja Lata',                      aliases:['cerveja lata','lata cerveja'],                                                  price: 7.0,  active:true, category:'BEBIDAS'    },
  { id:'ref001',  name:'Refrigerante Lata 350ml',           aliases:['refri lata','coca lata','guarana lata'],                                        price: 6.0,  active:true, category:'BEBIDAS'    },
  { id:'ref002',  name:'Refrigerante 600ml',                aliases:['coca 600','refri 600'],                                                         price: 9.0,  active:true, category:'BEBIDAS'    },
  { id:'ref003',  name:'Refrigerante 2L',                   aliases:['coca 2l','refri 2 litros'],                                                     price:18.0,  active:true, category:'BEBIDAS'    },
  { id:'agua001', name:'Água Mineral 500ml',                aliases:['agua','agua mineral'],                                                          price: 5.0,  active:true, category:'BEBIDAS'    },
];

const MenuService = {
  findProductByText(text) {
    const t = normalizeText(text);
    return MOCK_PRODUCTS.find(p => p.active && (
      t.includes(normalizeText(p.name)) ||
      p.aliases.some(a => t.includes(normalizeText(a)))
    )) || null;
  },
  findSimilarProducts(text) {
    const t = normalizeText(text);
    const words = t.split(' ').filter(w => w.length > 2);
    return MOCK_PRODUCTS.filter(p => p.active && words.some(w =>
      normalizeText(p.name).includes(w) ||
      p.aliases.some(a => normalizeText(a).includes(w))
    )).slice(0, 3);
  },
  getProductById(id) { return MOCK_PRODUCTS.find(p => p.id === id) || null; },
  listActiveProducts() { return MOCK_PRODUCTS.filter(p => p.active); },
  calculateItemsTotal(items) { return items.reduce((sum, i) => sum + (i.subtotal || 0), 0); }
};

// ─── PDV ADAPTER stub ─────────────────────────────────────────────────────────
const PDVAdapter = {
  createOrder(orderState) {
    // TODO: PDV — descomentar quando integração real estiver pronta:
    // return await helpers.httpRequest({ method:'POST', url:`${PDV_URL}/orders`,
    //   headers:{'Content-Type':'application/json','Authorization':`Bearer ${PDV_TOKEN}`},
    //   body:JSON.stringify(orderState), json:true });
    return { success: true, orderId: 'MOCK-' + Date.now() };
  }
};

// ─── HELPERS ─────────────────────────────────────────────────────────────────
function extractQuantity(text) {
  const t = normalizeText(text);
  if (/\bmais (um|uma)\b/.test(t)) return 1;
  const numWords = { 'um': 1, 'uma': 1, 'dois': 2, 'duas': 2, 'tres': 3, 'quatro': 4, 'cinco': 5, 'seis': 6 };
  const nm = t.match(/(\d+)\s*x\s/) || t.match(/^(\d+)\s/) || t.match(/\s(\d+)\s*x?\s/);
  if (nm) return Math.max(1, Math.min(parseInt(nm[1]), 20));
  const words = t.split(' ');
  for (const [w, n] of Object.entries(numWords)) {
    if (words[0] === w || words.includes(w)) return n;
  }
  return 1;
}

function extractObservations(text) {
  const obs = [];
  const patterns = [
    /\bsem\s+\w+/gi,
    /\btirar\s+\w+/gi,
    /\bbem\s+passad[oa]/gi,
    /\bao\s+ponto/gi,
    /\bmal\s+passad[oa]/gi,
  ];
  for (const pat of patterns) {
    const found = text.match(pat) || [];
    obs.push(...found.map(o => o.trim()));
  }
  return [...new Set(obs)];
}

function addItemToOrder(orderState, product, quantity, observations) {
  const obsKey = [...observations].sort().join('|');
  const existing = orderState.items.find(
    i => i.productId === product.id && [...i.observations].sort().join('|') === obsKey
  );
  if (existing) {
    existing.quantity += quantity;
    existing.subtotal = existing.unitPrice * existing.quantity;
  } else {
    orderState.items.push({
      productId: product.id, name: product.name, quantity,
      unitPrice: product.price, observations, subtotal: product.price * quantity
    });
  }
  orderState.itemsTotal = MenuService.calculateItemsTotal(orderState.items);
}

function notFoundReply(text) {
  const similar = MenuService.findSimilarProducts(text);
  if (similar.length > 0) {
    return 'Esse não temos, mas temos ' + similar.map(p => p.name).join(' e ') + ' 👍 Quer algum desses?';
  }
  return 'Hmm, não encontrei esse item. Dá uma olhada no cardápio 👇\n' + LINK_CARDAPIO + '\nMe fala o que vai querer!';
}

function fmtR(v) { return 'R$ ' + v.toFixed(2).replace('.', ','); }

function buildSummary(os) {
  let itens = '';
  for (const item of os.items) {
    const obs = item.observations.length ? ' (' + item.observations.join(', ') + ')' : '';
    itens += item.quantity + 'x ' + item.name + obs + ' — ' + fmtR(item.subtotal) + '\n';
  }
  const total = fmtR(os.itemsTotal);
  let entrega = '';
  if (os.deliveryType === 'delivery') {
    const end = os.address || (os.gpsLocation ? 'GPS ' + os.gpsLocation.lat + ',' + os.gpsLocation.lng : 'a confirmar');
    entrega = 'Entrega: ' + end + '\n';
  } else {
    entrega = 'Retirada no local 🏃\n';
  }
  const pgto = os.paymentMethod ? 'Pagamento: ' + os.paymentMethod + '\n' : '';
  const frete = os.deliveryType === 'delivery' ? ' + frete' : '';
  return 'Ficou assim 👇\n' + itens + entrega + pgto + 'Total: ' + total + frete;
}

function newOS() {
  return { items: [], deliveryType: null, address: null, gpsLocation: null,
           paymentMethod: null, changeFor: null, itemsTotal: 0, deliveryFee: 0, grandTotal: 0, status: 'draft' };
}

// ─── MEMÓRIA ─────────────────────────────────────────────────────────────────
if (!staticData.memoriaClientes) staticData.memoriaClientes = {};
const memoria = staticData.memoriaClientes;
const numero = dados.remoteJid;
const RESET_2H = 2 * 60 * 60 * 1000;
if (!memoria[numero] || (Date.now() - (memoria[numero].ultima_interacao || 0) > RESET_2H)) {
  memoria[numero] = { estado: 'inicio', ultima_intencao: null, etapa: 'nova_conversa',
    orderState: newOS(), lastItemAdded: null, ultima_interacao: Date.now() };
}
const cliente = memoria[numero];
cliente.ultima_interacao = Date.now();
if (!cliente.orderState) cliente.orderState = newOS();
if (!('lastItemAdded' in cliente)) cliente.lastItemAdded = null;

// ENCERRAMENTO
if (/obrigad|tchau|valeu|at[eé] logo|flw|at[eé] mais|xau/.test(msg)) {
  if (sessao) { sessao.historico = []; sessao.estado = 'inicio'; }
  memoria[numero] = { estado: 'inicio', ultima_intencao: null, etapa: 'nova_conversa',
    orderState: newOS(), lastItemAdded: null, ultima_interacao: Date.now() };
  const dp = ['Disponha! 😊 Qualquer coisa é só chamar.', 'Até logo! Volte sempre 👋', 'Foi um prazer! 😊'];
  return [{ json: { ...dados, textoResposta: dp[Math.floor(Math.random() * dp.length)], chamarLLM: false } }];
}

// ─── OBSERVAÇÃO SEM PRODUTO (aplicar ao último item) ─────────────────────────
if (
  (cliente.etapa === 'aguardando_complemento' || cliente.etapa === 'aguardando_item') &&
  cliente.lastItemAdded && !MenuService.findProductByText(msg)
) {
  const obs = extractObservations(msgOrig);
  if (obs.length > 0) {
    const last = cliente.orderState.items.find(i => i.productId === cliente.lastItemAdded);
    if (last) {
      last.observations.push(...obs.filter(o => !last.observations.includes(o)));
      return [{ json: { ...dados, textoResposta: 'Anotado: ' + obs.join(', ') + ' no ' + last.name + ' ✅\nMais alguma coisa?', chamarLLM: false } }];
    }
  }
}

// ─── FLUXO DE PEDIDO ─────────────────────────────────────────────────────────

if (cliente.etapa === 'aguardando_item') {
  const quantity = extractQuantity(msgOrig);
  const product = MenuService.findProductByText(msg);
  const observations = extractObservations(msgOrig);
  if (product) {
    addItemToOrder(cliente.orderState, product, quantity, observations);
    cliente.lastItemAdded = product.id;
    cliente.etapa = 'aguardando_complemento';
    const obsText = observations.length ? ' (' + observations.join(', ') + ')' : '';
    return [{ json: { ...dados, textoResposta: 'Anotado: ' + quantity + 'x ' + product.name + obsText + ' 😊\nQuer adicionar alguma bebida ou acompanhamento?', chamarLLM: false } }];
  }
  return [{ json: { ...dados, textoResposta: notFoundReply(msg), chamarLLM: false } }];
}

if (cliente.etapa === 'aguardando_complemento') {
  if (/n[ãa]o|s[óo] isso|pode fechar|sem mais|t[áa] [óo]timo|t[áa] bom|pode|fechou/.test(msg)) {
    cliente.etapa = 'aguardando_tipo_entrega';
    return [{ json: { ...dados, textoResposta: 'Certo! 👍 Vai ser entrega ou você retira aqui?', chamarLLM: false } }];
  }
  const quantity = extractQuantity(msgOrig);
  const product = MenuService.findProductByText(msg);
  const observations = extractObservations(msgOrig);
  if (product) {
    addItemToOrder(cliente.orderState, product, quantity, observations);
    cliente.lastItemAdded = product.id;
    const obsText = observations.length ? ' (' + observations.join(', ') + ')' : '';
    return [{ json: { ...dados, textoResposta: 'Anotado: ' + quantity + 'x ' + product.name + obsText + ' 👍\nMais alguma coisa ou pode fechar?', chamarLLM: false } }];
  }
  cliente.etapa = 'aguardando_tipo_entrega';
  return [{ json: { ...dados, textoResposta: 'Ótimo! Vai ser entrega ou você retira aqui? 🛵', chamarLLM: false } }];
}

if (cliente.etapa === 'aguardando_tipo_entrega') {
  if (/retir|buscar|pass(o|ar)|l[áa] eu|vou at[eé]|pego|retirad/.test(msg)) {
    cliente.orderState.deliveryType = 'retirada'; cliente.orderState.deliveryFee = 0;
    cliente.etapa = 'aguardando_pagamento';
    return [{ json: { ...dados, textoResposta: 'Retirada anotada 👍 Como vai pagar? Dinheiro, PIX ou cartão?', chamarLLM: false } }];
  }
  cliente.orderState.deliveryType = 'delivery';
  cliente.etapa = 'aguardando_endereco';
  return [{ json: { ...dados, textoResposta: 'Me passa o endereço completo 📍 Rua, número e bairro.', chamarLLM: false } }];
}

if (cliente.etapa === 'aguardando_endereco') {
  if (msg === '__localizacao__' && dados.localizacao) {
    cliente.orderState.gpsLocation = dados.localizacao; cliente.orderState.address = null;
  } else { cliente.orderState.address = msgOrig; cliente.orderState.gpsLocation = null; }
  cliente.orderState.deliveryFee = 0; // TODO: PDV — calcular frete via API
  cliente.etapa = 'aguardando_pagamento';
  return [{ json: { ...dados, textoResposta: 'Endereço anotado 📍 Como vai pagar? Dinheiro, PIX ou cartão?', chamarLLM: false } }];
}

if (cliente.etapa === 'aguardando_pagamento') {
  let metodo = null;
  if (/pix/.test(msg)) metodo = 'PIX';
  else if (/dinheiro|especie/.test(msg)) metodo = 'Dinheiro';
  else if (/cart[ãa]o|credito|debito/.test(msg)) metodo = 'Cartão';
  if (!metodo) return [{ json: { ...dados, textoResposta: 'Pode pagar com Dinheiro, PIX ou Cartão — qual prefere? 💳', chamarLLM: false } }];
  cliente.orderState.paymentMethod = metodo;
  cliente.orderState.grandTotal = cliente.orderState.itemsTotal + cliente.orderState.deliveryFee;
  cliente.etapa = 'aguardando_confirmacao';
  return [{ json: { ...dados, textoResposta: buildSummary(cliente.orderState) + '\n\nConfirmo o pedido? 😊', chamarLLM: false } }];
}

if (cliente.etapa === 'aguardando_confirmacao') {
  if (/sim|pode|confirm|fechou|isso mesmo|t[áa] bom|t[áa] [óo]timo|ok/.test(msg)) {
    cliente.orderState.status = 'confirmed';
    // TODO: PDV — PDVAdapter.createOrder(cliente.orderState);
    cliente.etapa = 'pedido_fechado';
    if (sessao) sessao.estado = 'inicio';
    return [{ json: { ...dados, textoResposta: 'Pedido confirmado! 🎉 Já estamos preparando tudo. Qualquer novidade te aviso aqui 😊', chamarLLM: false } }];
  }
  if (/n[ãa]o|cancel|errad|mud/.test(msg)) {
    cliente.etapa = 'aguardando_item'; cliente.orderState = newOS(); cliente.lastItemAdded = null;
    return [{ json: { ...dados, textoResposta: 'Sem problema! Me fala de novo o que você vai querer 😊', chamarLLM: false } }];
  }
  return [{ json: { ...dados, textoResposta: buildSummary(cliente.orderState) + '\n\nPosso confirmar? 👍', chamarLLM: false } }];
}

// ─── INTENÇÕES FIXAS ──────────────────────────────────────────────────────────

if (/card[áa]pio|o que tem|ver (os )?pratos?|quais s[ãa]o|o que serve/.test(msg)) {
  cliente.ultima_intencao = 'cardapio';
  return [{ json: { ...dados, textoResposta: 'Aqui está nosso cardápio 👇\n' + LINK_CARDAPIO + '\n\nViu algo que gostou? Me fala que eu anoto 😊', chamarLLM: false } }];
}

if (/quero( pedir)?|vou querer|p[eê]d(e|ir)|me manda|manda (um|uma|o|a)|queria( pedir)?/.test(msg)) {
  cliente.etapa = 'aguardando_item'; cliente.orderState = newOS(); cliente.lastItemAdded = null;
  if (sessao) sessao.estado = 'pedido';
  const quantity = extractQuantity(msgOrig);
  const product = MenuService.findProductByText(msg);
  const observations = extractObservations(msgOrig);
  if (product) {
    addItemToOrder(cliente.orderState, product, quantity, observations);
    cliente.lastItemAdded = product.id;
    cliente.etapa = 'aguardando_complemento';
    const obsText = observations.length ? ' (' + observations.join(', ') + ')' : '';
